var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"SEOYOON_ALT_NULL_NULL","text":{"KOREA":"......알았다니까?","JPN":"……わかったって。","ENG":"I told you, I got it!","TWN":"……知道了？"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"sfx":"FX_CUTSCEN_NOISE"},{"id":"L3_1","type":"dialog","speaker":"SEOYOON_ALT_NULL_NULL","text":{"KOREA":".......","JPN":"……","ENG":".......","TWN":"……"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L4_1","type":"dialog","speaker":"SEOYOON_ALT_NULL_NULL","text":{"KOREA":"말했었지? 내 방식대로 처리한다고. 쓸데없는 참견은 사양하겠어.","JPN":"言ったでしょ？　私のやり方で始末するって。\\n余計なお世話はご免だから。","ENG":"Like I said... I’m going to do this my way. Stay out of it.","TWN":"我說過了吧？就說用我的方式處理，不需要你多管閒事。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L5_1","type":"dialog","speaker":"SEOYOON_ALT_NULL_NULL","text":{"KOREA":"그쪽이 한 약속이나 잊지 마.","JPN":"そっちこそ、約束忘れないでよ。","ENG":"Just don't forget to keep your end of the bargain.","TWN":"請不要忘記你那邊的承諾。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L6_1","type":"dialog","speaker":"SEOYOON_ALT_NULL_NULL","text":{"KOREA":".......","JPN":"……","ENG":".......","TWN":"……"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L9_1","type":"dialog","speaker":"YOOJIN_ALT_NULL_NULL","text":{"KOREA":"......대장?","JPN":"……隊長？","ENG":"Cap?","TWN":"……隊長？"},"stage":{"bg":"DOCK_CLOUDY","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOJIN_ALT_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"SEOYOON_ALT_NULL_NULL","text":{"KOREA":"......유진아?","JPN":"……シロコ？","ENG":"Oh, hey Eujin.","TWN":"……劉珍？"},"stage":{"bg":"DOCK_CLOUDY","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEOYOON_ALT_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"YOOJIN_ALT_NULL_NULL","text":{"KOREA":"토, 통화 중이었나 보네.","JPN":"で、電話中だったのか。","ENG":"I-I didn’t know you were on the phone.","TWN":"妳、妳在講電話啊……"},"stage":{"bg":"DOCK_CLOUDY","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOJIN_ALT_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"YOOJIN_ALT_NULL_NULL","text":{"KOREA":"미안...... 내가 방해를......","JPN":"ごめん、邪魔して……","ENG":"Sorry... I hope I didn’t interrupt...","TWN":"對不起……打擾了……"},"stage":{"bg":"DOCK_CLOUDY","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOJIN_ALT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"SEOYOON_ALT_NULL_NULL","text":{"KOREA":"......","JPN":"……","ENG":"......","TWN":"……"},"stage":{"bg":"DOCK_CLOUDY","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEOYOON_ALT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"SEOYOON_ALT_NULL_NULL","text":{"KOREA":"어디까지 들었어?","JPN":"どこまで聞いてたの？","ENG":"How much of that did you hear?","TWN":"妳聽到了多少？"},"stage":{"bg":"DOCK_CLOUDY","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEOYOON_ALT_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"YOOJIN_ALT_NULL_NULL","text":{"KOREA":"따, 딱히 아무것도......","JPN":"と、とくに何も……","ENG":"N-not much, really...","TWN":"沒、沒聽到什麼特別的……"},"stage":{"bg":"DOCK_CLOUDY","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOJIN_ALT_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"SOYEONG_POLICE_NULL_NULL","text":{"KOREA":"안녕하세요!","JPN":"こんにちは！","ENG":"Hello!","TWN":"你們好！"},"stage":{"bg":"DOCK_CLOUDY","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SOYEONG_POLICE_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"SEOYOON_ALT_NULL_NULL","text":{"KOREA":".......","JPN":"……","ENG":".......","TWN":"……"},"stage":{"bg":"DOCK_CLOUDY","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEOYOON_ALT_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"SOYEONG_POLICE_NULL_NULL","text":{"KOREA":"이야...... 덕분에 살았다니까요.","JPN":"いやあ……おかげさまで助かりましたよ。","ENG":"Gee-whiz! You saved our butts.","TWN":"唉呀……多虧了你們，我們才活了下來。"},"stage":{"bg":"DOCK_CLOUDY","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SEOYOON_ALT_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SOYEONG_POLICE_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L21_1","type":"dialog","speaker":"SOYEONG_POLICE_NULL_NULL","text":{"KOREA":"분명, 알트 소대 분들이라고 하셨죠?","JPN":"たしか、アルト小隊とおっしゃってましたよね？","ENG":"You guys are the ALT Squad, right?","TWN":"你們是阿爾特小隊吧？"},"stage":{"bg":"DOCK_CLOUDY","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SEOYOON_ALT_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SOYEONG_POLICE_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L22_1","type":"dialog","speaker":"SOYEONG_POLICE_NULL_NULL","text":{"KOREA":"지원 오시는 게 조금만 늦었으면 저 같은 일반인은 어떤 꼴을 당했을지......","JPN":"支援が少しでも遅れてたら、私みたいな一般人はどんな目にあっていたか……","ENG":"If you got here a moment later, well, a non-powered gal like me wouldn’t have stood a chance...","TWN":"要是你們的支援再來得晚一點，像我這樣的一般人不知道會變成什麼鬼樣子……"},"stage":{"bg":"DOCK_CLOUDY","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SEOYOON_ALT_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SOYEONG_POLICE_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L23_1","type":"dialog","speaker":"SEOYOON_ALT_NULL_NULL","text":{"KOREA":"......저야말로 늦지 않게 도착해서 다행이에요.","JPN":"……こちらこそ間に合って良かったです。","ENG":"I’m glad we made it on time as well.","TWN":"……我才慶幸我們能夠及時趕到。"},"stage":{"bg":"DOCK_CLOUDY","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SEOYOON_ALT_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SOYEONG_POLICE_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L24_1","type":"dialog","speaker":"SEOYOON_ALT_NULL_NULL","text":{"KOREA":"그런데...... 성함이?","JPN":"ところで……お名前をお聞きしても？","ENG":"Anyway... You are?","TWN":"話說回來……妳叫什麼名字？"},"stage":{"bg":"DOCK_CLOUDY","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SEOYOON_ALT_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SOYEONG_POLICE_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L25_1","type":"dialog","speaker":"SOYEONG_POLICE_NULL_NULL","text":{"KOREA":"강소영 경위라고 해요.","JPN":"警部補のマエカワ・ナツミです。","ENG":"Lieutenant Kang Soyoung, at your service.","TWN":"我是姜素英警衛。"},"stage":{"bg":"DOCK_CLOUDY","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SEOYOON_ALT_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SOYEONG_POLICE_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L26_1","type":"dialog","speaker":"SOYEONG_POLICE_NULL_NULL","text":{"KOREA":"경찰청, 카운터 범죄 수사반 소속 경찰입니다.","JPN":"警察庁、カウンター犯罪捜査班所属です。","ENG":"I’m with the Counters investigation team of the police.","TWN":"是警察廳制裁者犯罪搜查班的警察。"},"stage":{"bg":"DOCK_CLOUDY","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SEOYOON_ALT_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SOYEONG_POLICE_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L27_1","type":"dialog","speaker":"SEOYOON_ALT_NULL_NULL","text":{"KOREA":"아, 경찰이시군요.","JPN":"あ、警察の方なんですね。","ENG":"Oh, so you're a police officer.","TWN":"啊，原來是警察啊。"},"stage":{"bg":"DOCK_CLOUDY","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SEOYOON_ALT_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SOYEONG_POLICE_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L28_1","type":"dialog","speaker":"SEOYOON_ALT_NULL_NULL","text":{"KOREA":"반갑습니다. 앞으로 잘 부탁드려요.","JPN":"はじめまして。これからよろしくお願いします。","ENG":"Nice to meet you. I look forward to working with you.","TWN":"很高興見到妳。接下來就請多多指教囉。"},"stage":{"bg":"DOCK_CLOUDY","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SEOYOON_ALT_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SOYEONG_POLICE_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L29_1","type":"dialog","speaker":"SOYEONG_POLICE_NULL_NULL","text":{"KOREA":"하하, 뭘요. 이런 상황에서는 오히려 제가 부탁드려야죠.","JPN":"はは、こんな状況ですから。\\nこちらこそよろしくお願いいたします。","ENG":"Haha, thank you. Really, the honor is all mine.","TWN":"哈哈，太客氣了。這種情況反而是我要請你們多多指教呢。"},"stage":{"bg":"DOCK_CLOUDY","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SEOYOON_ALT_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SOYEONG_POLICE_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L30_1","type":"dialog","speaker":"SOYEONG_POLICE_NULL_NULL","text":{"KOREA":"그런데...... 조금 전에는 누구와 통화하고 계셨던 건가요?","JPN":"ところで、先ほどは誰と通話していたのですか？","ENG":"Anyway... Who were you talking to on the phone just now?","TWN":"不過……妳之前在和誰講電話啊？"},"stage":{"bg":"DOCK_CLOUDY","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SEOYOON_ALT_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SOYEONG_POLICE_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L31_1","type":"dialog","speaker":"SEOYOON_ALT_NULL_NULL","text":{"KOREA":"......네?","JPN":"……はい？","ENG":"...Sorry?","TWN":"……咦？"},"stage":{"bg":"DOCK_CLOUDY","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SEOYOON_ALT_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"SOYEONG_POLICE_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L32_1","type":"dialog","speaker":"SOYEONG_POLICE_NULL_NULL","text":{"KOREA":"아아, 별건 아니고 지나가다가 우연히 보게 됐는데 말이죠.","JPN":"あ、いえ、通りすがりにたまたま見かけたのですが。","ENG":"Oh, it’s nothing. I just happened to grab a glimpse when I was passing by.","TWN":"啊，沒有什麼特別的意思，就是經過的時候碰巧看到。"},"stage":{"bg":"DOCK_CLOUDY","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SEOYOON_ALT_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"SOYEONG_POLICE_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L33_1","type":"dialog","speaker":"SOYEONG_POLICE_NULL_NULL","text":{"KOREA":"표정이 너무 굳어 있으신 것 같아서요.","JPN":"表情が非常に硬かったので。","ENG":"You had this grim look on your face, that’s all.","TWN":"妳講電話的時候表情看起來很嚴肅呢。"},"stage":{"bg":"DOCK_CLOUDY","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SEOYOON_ALT_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"SOYEONG_POLICE_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L34_1","type":"dialog","speaker":"SEOYOON_ALT_NULL_NULL","text":{"KOREA":"......","JPN":"……","ENG":"......","TWN":"……"},"stage":{"bg":"DOCK_CLOUDY","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SEOYOON_ALT_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SOYEONG_POLICE_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L35_1","type":"dialog","speaker":"SOYEONG_POLICE_NULL_NULL","text":{"KOREA":"대체 누구와 무슨 이야기를 하셨길래 그렇게 무서운 얼굴로......","JPN":"誰と何の話をしてたら、そんな恐ろしい顔に……","ENG":"I was just wondering whom you might have been speaking to, with such a scary look on your face...","TWN":"到底是在和誰講電話，才會露出那麼恐怖的表情……"},"stage":{"bg":"DOCK_CLOUDY","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SEOYOON_ALT_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SOYEONG_POLICE_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L37_1","type":"dialog","speaker":"YOOJIN_ALT_NULL_NULL","text":{"KOREA":"이봐! 당신 뭐 하는 거야?","JPN":"おい！　あんた何やってんだ？","ENG":"Hey! What are you doing?!","TWN":"喂！妳是怎樣？"},"stage":{"bg":"DOCK_CLOUDY","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOJIN_ALT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L38_1","type":"dialog","speaker":"YOOJIN_ALT_NULL_NULL","text":{"KOREA":"지금 취조라도 하는 거야? 이건 사생활 침해라고!","JPN":"取り調べでもしてるつもりか？　これはプライバシー侵害だ！","ENG":"Is this some kind of an interrogation? This is an invasion of privacy!","TWN":"現在是在審問嗎？妳這是侵犯隱私！"},"stage":{"bg":"DOCK_CLOUDY","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOJIN_ALT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L41_1","type":"dialog","speaker":"SEOYOON_ALT_NULL_NULL","text":{"KOREA":"......","JPN":"……","ENG":"......","TWN":"……"},"stage":{"bg":"DOCK_CLOUDY","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SEOYOON_ALT_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SOYEONG_POLICE_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L42_1","type":"dialog","speaker":"SOYEONG_POLICE_NULL_NULL","text":{"KOREA":"아...... 하하하. 그러게요.","JPN":"あ……ははは、たしかに。","ENG":"Oh... Hahaha... You’re right.","TWN":"啊，哈哈哈，對喔。"},"stage":{"bg":"DOCK_CLOUDY","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SEOYOON_ALT_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SOYEONG_POLICE_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L43_1","type":"dialog","speaker":"SOYEONG_POLICE_NULL_NULL","text":{"KOREA":"죄송해요. 제가 좀 주제넘었죠?","JPN":"すみません。私がちょっと出しゃばりましたよね？","ENG":"My apologies. I was out of line, wasn’t I?","TWN":"真是抱歉。我有點太冒昧了對吧？"},"stage":{"bg":"DOCK_CLOUDY","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SEOYOON_ALT_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SOYEONG_POLICE_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L44_1","type":"dialog","speaker":"SOYEONG_POLICE_NULL_NULL","text":{"KOREA":"직업이 직업이다 보니 질문하는 게 습관이 되어서요......","JPN":"職業柄、質問するのが癖になっていて……","ENG":"It just comes with the job. I can’t help but keep asking people questions.","TWN":"當警察當久了，一不小心就養成質問別人的習慣了……"},"stage":{"bg":"DOCK_CLOUDY","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SEOYOON_ALT_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SOYEONG_POLICE_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L45_1","type":"dialog","speaker":"SOYEONG_POLICE_NULL_NULL","text":{"KOREA":"불쾌하게 해 드렸다면 사과드릴게요.","JPN":"不愉快でしたらお詫びします。","ENG":"I’m sorry if I made you uncomfortable.","TWN":"如果造成妳的不快，那我向妳道歉吧。"},"stage":{"bg":"DOCK_CLOUDY","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SEOYOON_ALT_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SOYEONG_POLICE_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L46_1","type":"dialog","speaker":"SOYEONG_POLICE_NULL_NULL","text":{"KOREA":"정말 죄송합니다.","JPN":"本当に申し訳ありません。","ENG":"Terribly sorry.","TWN":"真是對不起。"},"stage":{"bg":"DOCK_CLOUDY","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SEOYOON_ALT_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SOYEONG_POLICE_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L48_1","type":"dialog","speaker":"YOOJIN_ALT_NULL_NULL","text":{"KOREA":"미안하다면 다인 줄 알아?","JPN":"詫びて終わる話か？","ENG":"Sorry won’t cut it, lady!","TWN":"說句對不起就可以了嗎？"},"stage":{"bg":"DOCK_CLOUDY","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOJIN_ALT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L1_1","type":"dialog","speaker":"SEOYOON_ALT_NULL_NULL","text":{"KOREA":"괜찮아 유진아.","JPN":"いいのよ、シロコ。","ENG":"It's okay, Eujin.","TWN":"沒事的，劉珍。"},"stage":{"bg":"DOCK_CLOUDY","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SEOYOON_ALT_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SOYEONG_POLICE_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L3_1","type":"dialog","speaker":"YOOJIN_ALT_NULL_NULL","text":{"KOREA":"하, 하지만......","JPN":"で、でも……","ENG":"B-but...","TWN":"但，但是……"},"stage":{"bg":"DOCK_CLOUDY","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOJIN_ALT_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"SEOYOON_ALT_NULL_NULL","text":{"KOREA":"말씀드릴게요. 그다지 비밀도 아니니까요.","JPN":"そんなに内密な話でもないので、お話ししますね。","ENG":"I can tell you. It’s not really much of a secret.","TWN":"就讓我來告訴妳吧。這其實也不能算是什麼秘密。"},"stage":{"bg":"DOCK_CLOUDY","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SEOYOON_ALT_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SOYEONG_POLICE_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L7_1","type":"dialog","speaker":"SEOYOON_ALT_NULL_NULL","text":{"KOREA":"사실 이번에 저희가 호위해야 할 참고인이......","JPN":"実は今回、私たちが守るべき参考人が……","ENG":"You see, the asset we're supposed to escort is...","TWN":"其實這次我們要護衛的證人……"},"stage":{"bg":"DOCK_CLOUDY","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SEOYOON_ALT_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SOYEONG_POLICE_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L8_1","type":"dialog","speaker":"SEOYOON_ALT_NULL_NULL","text":{"KOREA":"지난번 작전에서 절 납치했던 당사자라서요.","JPN":"この前の作戦で、私をさらった当事者なんです。","ENG":"...actually the same person who abducted me in our last operation.","TWN":"就是上次作戰時綁架了我的人。"},"stage":{"bg":"DOCK_CLOUDY","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SEOYOON_ALT_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SOYEONG_POLICE_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L9_1","type":"dialog","speaker":"SOYEONG_POLICE_NULL_NULL","text":{"KOREA":"......납치당한 적이 있으세요?","JPN":"……さらわれたことがあるんですか？","ENG":"You were abducted?","TWN":"……妳被綁架了？"},"stage":{"bg":"DOCK_CLOUDY","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SEOYOON_ALT_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SOYEONG_POLICE_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L10_1","type":"dialog","speaker":"SEOYOON_ALT_NULL_NULL","text":{"KOREA":"네, 그래서 담당 심리치료사와 좀 트러블이 있었어요.","JPN":"はい、そのことで担当の\\n心理カウンセラーとちょっと揉めていました。","ENG":"Yes. So I had a little discussion with my psychiatrist.","TWN":"是的，然後我和我的心理治療師就發生了點不愉快。"},"stage":{"bg":"DOCK_CLOUDY","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SEOYOON_ALT_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"SOYEONG_POLICE_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L11_1","type":"dialog","speaker":"SEOYOON_ALT_NULL_NULL","text":{"KOREA":"가해대상과 지속적인 근접 접촉을 하는 건 문제가 발생할 확률이 크다고......","JPN":"加害者と接触を繰り返すのは、\\n問題が生じる確率が高い、と……","ENG":"Apparently being in constant contact with my aggressor has a high chance of affecting my mental health negatively...","TWN":"說是和加害對象一直近距離接觸的話，發生問題的可能性很高……"},"stage":{"bg":"DOCK_CLOUDY","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SEOYOON_ALT_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SOYEONG_POLICE_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L12_1","type":"dialog","speaker":"SOYEONG_POLICE_NULL_NULL","text":{"KOREA":"그랬군요.","JPN":"そうだったんですね。","ENG":"I see.","TWN":"原來如此。"},"stage":{"bg":"DOCK_CLOUDY","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SEOYOON_ALT_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SOYEONG_POLICE_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L13_1","type":"dialog","speaker":"SEOYOON_ALT_NULL_NULL","text":{"KOREA":"하지만 실적도 나쁜데 계속 쉬기만 할 수도 없는 상황이라, 협상을 좀 했죠.","JPN":"でも、実績も悪いのにずっと休んでばかり\\nいるわけにもいかないので、交渉を持ちかけまして。","ENG":"But I couldn’t just stay benched like that, not when I’m already trailing behind on performance. So I made a little deal.","TWN":"但是我最近的業績不太好，也不能一直休息，所以在跟他交涉。"},"stage":{"bg":"DOCK_CLOUDY","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SEOYOON_ALT_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SOYEONG_POLICE_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L14_1","type":"dialog","speaker":"SEOYOON_ALT_NULL_NULL","text":{"KOREA":"이번 일을 문제 없이 마치면 심리치료 결과에 완치 판정을 내려주기로 말이죠.","JPN":"今回の仕事を問題なく完遂できたら、完治の判定をいただきたい、と。","ENG":"If I complete this mission without any trouble, they’ll certify me completely cured from the trauma.","TWN":"這次的事情順利完成的話，心理治療的結果就可以判定為完全治好了。"},"stage":{"bg":"DOCK_CLOUDY","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SEOYOON_ALT_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SOYEONG_POLICE_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L15_1","type":"dialog","speaker":"SOYEONG_POLICE_NULL_NULL","text":{"KOREA":"아하.","JPN":"なるほど。","ENG":"A-ha.","TWN":"原來如此。"},"stage":{"bg":"DOCK_CLOUDY","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SEOYOON_ALT_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SOYEONG_POLICE_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L16_1","type":"dialog","speaker":"SEOYOON_ALT_NULL_NULL","text":{"KOREA":"여러가지로 스트레스가 많은 상황이라 좀 날카로워졌나 보네요.","JPN":"色々ストレスが溜まっていたので、少し神経質になっていたかもしれません。","ENG":"I guess I've just been a bit on edge because of stress.","TWN":"也因為壓力有點大，所以我才會露出一臉嚴肅的表情。"},"stage":{"bg":"DOCK_CLOUDY","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SEOYOON_ALT_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SOYEONG_POLICE_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L17_1","type":"dialog","speaker":"SEOYOON_ALT_NULL_NULL","text":{"KOREA":"신경 쓰이게 만들었다면 죄송합니다.","JPN":"お気遣いすみません。","ENG":"Sorry if I misled you in any way.","TWN":"很抱歉讓妳擔心了。"},"stage":{"bg":"DOCK_CLOUDY","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SEOYOON_ALT_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SOYEONG_POLICE_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L18_1","type":"dialog","speaker":"SOYEONG_POLICE_NULL_NULL","text":{"KOREA":"하하, 아니에요. 저야말로 괜히 귀찮게 해드렸네요.","JPN":"はは、いえいえ。こちらこそお節介を焼いてすみません。","ENG":"Oh, don’t worry about it. If anything, I’m sorry for pestering you for no reason.","TWN":"哈哈，沒有。我才是多管閒事了呢。"},"stage":{"bg":"DOCK_CLOUDY","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SEOYOON_ALT_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SOYEONG_POLICE_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L19_1","type":"dialog","speaker":"SOYEONG_POLICE_NULL_NULL","text":{"KOREA":"이것도 직업병이라니까요. 고쳐야 하는데, 하하......","JPN":"これも職業病なんで、\\n治したいところですが、あはは……","ENG":"That also comes with the job. I really need to work on that, haha...","TWN":"看來這個職業病得改一改才行呢，哈哈……"},"stage":{"bg":"DOCK_CLOUDY","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SEOYOON_ALT_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SOYEONG_POLICE_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L20_1","type":"dialog","speaker":"SEOYOON_ALT_NULL_NULL","text":{"KOREA":"그럼 나중에 또 뵙죠.","JPN":"それではまた後で。","ENG":"Alright then. I’ll see you around.","TWN":"那麼下次再見吧。"},"stage":{"bg":"DOCK_CLOUDY","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SEOYOON_ALT_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SOYEONG_POLICE_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L21_1","type":"dialog","speaker":"SOYEONG_POLICE_NULL_NULL","text":{"KOREA":"알겠습니다.","JPN":"了解いたしました。","ENG":"Will do.","TWN":"好的。"},"stage":{"bg":"DOCK_CLOUDY","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SEOYOON_ALT_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SOYEONG_POLICE_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L23_1","type":"dialog","speaker":"YOOJIN_ALT_NULL_NULL","text":{"KOREA":"......","JPN":"……","ENG":"......","TWN":"……"},"stage":{"bg":"DOCK_CLOUDY","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOJIN_ALT_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"SOYEONG_POLICE_NULL_NULL","text":{"KOREA":"흐음......","JPN":"ふむ……","ENG":"Hmm...","TWN":"嗯……"},"stage":{"bg":"DOCK_CLOUDY","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SOYEONG_POLICE_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"SOYEONG_POLICE_NULL_NULL","text":{"KOREA":"납치라......","JPN":"さらわれていたのか……","ENG":"Abducted, huh...","TWN":"綁架……"},"stage":{"bg":"DOCK_CLOUDY","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SOYEONG_POLICE_NULL_NULL","face":"UNIT_IDLE"},"R":null}}}]`);export{e as default};